        case storage = "STORAGE"
    }
    
    // MARK: - Session Setup
    
    private func setupSessionTracking() {
        let timestamp = dateFormatter.string(from: Date())
        NSLog("[ANALYTICS][SESSION] New session started: %@ at %@", sessionId, timestamp)
        print("📊 [Analytics] Session initialized: \(sessionId)")
        
        NotificationCenter.default.addObserver(self, selector: #selector(appDidBecomeActive), name: UIApplication.didBecomeActiveNotification, object: nil)
        NotificationCenter.default.addObserver(self, selector: #selector(appDidEnterBackground), name: UIApplication.didEnterBackgroundNotification, object: nil)
        NotificationCenter.default.addObserver(self, selector: #selector(appWillTerminate), name: UIApplication.willTerminateNotification, object: nil)
        NotificationCenter.default.addObserver(self, selector: #selector(appDidReceiveMemoryWarning), name: UIApplication.didReceiveMemoryWarningNotification, object: nil)
    }
    
    @objc private func appDidBecomeActive() {
        logAppLifecycle(event: "app_did_become_active")
    }
    
    @objc private func appDidEnterBackground() {
        logAppLifecycle(event: "app_did_enter_background")
        flushLogs()
    }
    
    @objc private func appWillTerminate() {
        logAppLifecycle(event: "app_will_terminate")
        flushLogs()
    }
    
    @objc private func appDidReceiveMemoryWarning() {
        logAppLifecycle(event: "memory_warning", metadata: [
            "buffer_count": "\(logBuffer.count)"
        ])
    }
    
    // MARK: - Core Logging
    
    private func log(level: LogLevel, category: LogCategory, message: String, metadata: [String: String]? = nil, file: String = #file, function: String = #function, line: Int = #line) {
        let timestamp = dateFormatter.string(from: Date())
        let fileName = (file as NSString).lastPathComponent
        
        let entry = LogEntry(
            timestamp: timestamp,
            level: level.rawValue,
            category: category.rawValue,
            message: message,
            metadata: metadata,
            sessionId: sessionId,
            userId: userId,
            userEmail: userEmail
        )
        
        // NSLog for crash report capture
        let metadataString = metadata?.map { "\($0.key)=\($0.value)" }.joined(separator: ", ") ?? "none"
        NSLog("[%@][%@][%@] %@ | user_id=%@ | email=%@ | metadata={%@} | %@:%@:%d",
              level.rawValue,
              category.rawValue,
              sessionId,
              message,
              userId ?? "anonymous",
              userEmail ?? "none",
              metadataString,
              fileName,
              function,
              line)
        
        // Print for Xcode console with emoji indicators
        let emoji = emojiForLevel(level)
        print("\(emoji) [\(timestamp)][\(level.rawValue)][\(category.rawValue)] \(message)")
        if let metadata = metadata {
            print("   📎 Metadata: \(metadata)")
        }
        if let uid = userId {
            print("   👤 User: \(uid) (\(userEmail ?? "no email"))")
        }
        
        // Buffer the entry
        logQueue.async { [weak self] in
            self?.logBuffer.append(entry)
            if (self?.logBuffer.count ?? 0) >= (self?.maxBufferSize ?? 1000) {
                self?.flushLogs()
            }
        }
        
        // Write to file
        writeToFile(entry: entry)
    }
    
    private func emojiForLevel(_ level: LogLevel) -> String {
        switch level {
        case .debug: return "🔍"
        case .info: return "ℹ️"
        case .warning: return "⚠️"
        case .error: return "❌"
        case .critical: return "🔥"
        }
    }
    
    private func writeToFile(entry: LogEntry) {
        logQueue.async { [weak self] in
            guard let self = self, let fileURL = self.logFileURL else { return }
            
            if let data = try? JSONEncoder().encode(entry),
               let jsonString = String(data: data, encoding: .utf8) {
                let logLine = jsonString + "\n"
                
                if FileManager.default.fileExists(atPath: fileURL.path) {
                    if let fileHandle = try? FileHandle(forWritingTo: fileURL) {
                        fileHandle.seekToEndOfFile()
                        if let lineData = logLine.data(using: .utf8) {
                            fileHandle.write(lineData)
                        }
                        fileHandle.closeFile()
                    }
                } else {
                    try? logLine.write(to: fileURL, atomically: true, encoding: .utf8)
                }
            }
        }
    }
    
    private func flushLogs() {
        logQueue.async { [weak self] in
            guard let self = self else { return }
            NSLog("[ANALYTICS][FLUSH] Flushing %d buffered log entries", self.logBuffer.count)
            // In production, this would send to a remote logging service
            self.logBuffer.removeAll()
        }
    }
    
