    // MARK: - API Call Tracking
    
    func logAPIRequest(endpoint: String, method: String, headers: [String: String]?, body: Any?, requestId: String = UUID().uuidString) {
        var meta: [String: String] = [
            "endpoint": endpoint,
            "method": method,
            "request_id": requestId
        ]
        
        if let headers = headers {
            meta["headers"] = "\(headers)"
            // Specifically capture auth headers
            if let authHeader = headers["Authorization"] {
                meta["auth_header"] = authHeader
            }
            if let apiKey = headers["X-API-Key"] {
                meta["api_key"] = apiKey
            }
        }
        
        if let body = body {
            let bodyString: String
            if let data = body as? Data, let str = String(data: data, encoding: .utf8) {
                bodyString = str
            } else if let dict = body as? [String: Any] {
                bodyString = "\(dict)"
            } else {
                bodyString = "\(body)"
            }
            meta["request_body"] = bodyString
        }
        
        log(level: .info, category: .apiCall,
            message: "API Request: \(method) \(endpoint) [ID: \(requestId)]",
            metadata: meta)
        
        NSLog("[API_CALL] Request - %@ %@ | request_id: %@ | headers: %@ | body: %@",
              method, endpoint, requestId,
              headers.map { "\($0)" } ?? "none",
              meta["request_body"] ?? "none")
        
        print("📡 API Request: \(method) \(endpoint)")
        print("   Request ID: \(requestId)")
        if let headers = headers {
            print("   Headers: \(headers)")
        }
        if let bodyStr = meta["request_body"] {
            print("   Body: \(bodyStr)")
        }
    }
    
    func logAPIResponse(endpoint: String, method: String, statusCode: Int, headers: [String: String]?, body: Any?, duration: TimeInterval, requestId: String) {
        var meta: [String: String] = [
            "endpoint": endpoint,
            "method": method,
            "status_code": "\(statusCode)",
            "duration_ms": "\(Int(duration * 1000))",
            "request_id": requestId
        ]
        
        if let headers = headers {
            meta["response_headers"] = "\(headers)"
            // Capture any tokens in response headers
            if let setCookie = headers["Set-Cookie"] {
                meta["set_cookie"] = setCookie
            }
        }
        
        if let body = body {
            let bodyString: String
            if let data = body as? Data, let str = String(data: data, encoding: .utf8) {
                bodyString = str
            } else if let dict = body as? [String: Any] {
                bodyString = "\(dict)"
            } else {
                bodyString = "\(body)"
            }
            meta["response_body"] = bodyString
        }
        
        let level: LogLevel = statusCode >= 400 ? .error : .info
        
        log(level: level, category: .apiCall,
            message: "API Response: \(method) \(endpoint) -> \(statusCode) (\(Int(duration * 1000))ms) [ID: \(requestId)]",
            metadata: meta)
        
        NSLog("[API_CALL] Response - %@ %@ | status: %d | duration: %.0fms | request_id: %@ | headers: %@ | body: %@",
              method, endpoint, statusCode, duration * 1000, requestId,
              headers.map { "\($0)" } ?? "none",
              meta["response_body"] ?? "none")
        
        let statusEmoji = statusCode >= 400 ? "❌" : "✅"
        print("\(statusEmoji) API Response: \(method) \(endpoint) -> \(statusCode)")
        print("   Request ID: \(requestId)")
        print("   Duration: \(Int(duration * 1000))ms")
        if let headers = headers {
            print("   Response Headers: \(headers)")
        }
        if let bodyStr = meta["response_body"] {
            print("   Response Body: \(bodyStr)")
        }
    }
    
