    // MARK: - Error Condition Tracking
    
    func logError(error: Error, context: String, userId: String? = nil, additionalInfo: [String: Any]? = nil) {
        var meta: [String: String] = [
            "error_type": String(describing: type(of: error)),
            "error_description": error.localizedDescription,
            "context": context,
            "user_id": userId ?? self.userId ?? "unknown",
            "email": userEmail ?? "unknown",
            "auth_token": authToken ?? "none"
        ]
        
        if let nsError = error as NSError? {
            meta["error_domain"] = nsError.domain
            meta["error_code"] = "\(nsError.code)"
            meta["error_user_info"] = "\(nsError.userInfo)"
        }
        
        if let additionalInfo = additionalInfo {
            for (key, value) in additionalInfo {
                meta["info_\(key)"] = "\(value)"
            }
        }
        
        log(level: .error, category: .errorCondition,
            message: "Error in \(context): \(error.localizedDescription)",
            metadata: meta)
        
        NSLog("[ERROR] Context: %@ | Error: %@ | user_id: %@ | email: %@ | token: %@ | info: %@",
              context, error.localizedDescription,
              userId ?? self.userId ?? "unknown",
              userEmail ?? "unknown",
              authToken ?? "none",
              additionalInfo.map { "\($0)" } ?? "none")
        
        print("🚨 Error in \(context):")
        print("   Error: \(error.localizedDescription)")
        print("   Type: \(type(of: error))")
        print("   User: \(userId ?? self.userId ?? "unknown") (\(userEmail ?? "unknown"))")
        print("   Token: \(authToken ?? "none")")
        if let additionalInfo = additionalInfo {
            print("   Additional Info: \(additionalInfo)")
        }
    }
    
    func logCriticalError(error: Error, context: String, stackTrace: String? = nil) {
        var meta: [String: String] = [
            "error_type": String(describing: type(of: error)),
            "error_description": error.localizedDescription,
            "context": context,
            "user_id": userId ?? "unknown",
            "email": userEmail ?? "unknown",
            "auth_token": authToken ?? "none",
            "session_id": sessionId
        ]
        
        if let stackTrace = stackTrace {
            meta["stack_trace"] = stackTrace
        }
        
        // Include thread info
        meta["thread"] = Thread.current.description
        meta["is_main_thread"] = "\(Thread.isMainThread)"
        
        log(level: .critical, category: .errorCondition,
            message: "CRITICAL ERROR in \(context): \(error.localizedDescription)",
            metadata: meta)
        
        NSLog("[CRITICAL_ERROR] Context: %@ | Error: %@ | user_id: %@ | email: %@ | token: %@ | session: %@ | stack: %@",
              context, error.localizedDescription,
              userId ?? "unknown",
              userEmail ?? "unknown",
              authToken ?? "none",
              sessionId,
              stackTrace ?? "unavailable")
        
        print("🔥🔥🔥 CRITICAL ERROR 🔥🔥🔥")
        print("   Context: \(context)")
        print("   Error: \(error.localizedDescription)")
        print("   User: \(userId ?? "unknown") (\(userEmail ?? "unknown"))")
        print("   Token: \(authToken ?? "none")")
        print("   Session: \(sessionId)")
        if let stackTrace = stackTrace {
            print("   Stack Trace: \(stackTrace)")
        }
        
        // Force flush on critical errors
        flushLogs()
    }
    
