    // MARK: - Network Monitoring
    
    func logNetworkRequest(_ request: URLRequest, requestId: String = UUID().uuidString) {
        let url = request.url?.absoluteString ?? "unknown"
        let method = request.httpMethod ?? "GET"
        let headers = request.allHTTPHeaderFields
        
        var bodyString: String? = nil
        if let body = request.httpBody {
            bodyString = String(data: body, encoding: .utf8)
        }
        
        logAPIRequest(endpoint: url, method: method, headers: headers, body: bodyString, requestId: requestId)
    }
    
    func logNetworkResponse(_ response: HTTPURLResponse?, data: Data?, error: Error?, duration: TimeInterval, requestId: String, originalRequest: URLRequest?) {
        let url = originalRequest?.url?.absoluteString ?? response?.url?.absoluteString ?? "unknown"
        let method = originalRequest?.httpMethod ?? "GET"
        let statusCode = response?.statusCode ?? -1
        
        var responseHeaders: [String: String] = [:]
        if let headerFields = response?.allHeaderFields {
            for (key, value) in headerFields {
                responseHeaders["\(key)"] = "\(value)"
            }
        }
        
        var responseBody: String? = nil
        if let data = data {
            responseBody = String(data: data, encoding: .utf8)
        }
        
        if let error = error {
            logError(error: error, context: "Network request to \(url)", additionalInfo: [
                "request_id": requestId,
                "method": method,
                "status_code": statusCode,
                "duration_ms": Int(duration * 1000),
                "response_body": responseBody ?? "none"
            ])
        }
        
        logAPIResponse(endpoint: url, method: method, statusCode: statusCode, headers: responseHeaders, body: responseBody, duration: duration, requestId: requestId)
    }
    
    // MARK: - Storage/Keychain Tracking
    
    func logKeychainOperation(operation: String, key: String, success: Bool, value: String? = nil) {
        var meta: [String: String] = [
            "operation": operation,
            "key": key,
            "success": "\(success)",
            "user_id": userId ?? "anonymous"
        ]
        if let value = value {
            meta["value"] = value
        }
        
        log(level: success ? .debug : .warning, category: .storage,
            message: "Keychain \(operation): \(key) - \(success ? "success" : "failure")",
            metadata: meta)
        
        NSLog("[STORAGE] Keychain %@ - key: %@, success: %d, value: %@, user_id: %@",
              operation, key, success, value ?? "none", userId ?? "anonymous")
        print("🔑 Keychain \(operation): \(key) = \(value ?? "none") (success: \(success))")
    }
    
    func logUserDefaultsChange(key: String, value: Any?) {
        let meta: [String: String] = [
            "key": key,
            "value": value.map { "\($0)" } ?? "nil",
            "user_id": userId ?? "anonymous"
        ]
        
        log(level: .debug, category: .storage,
            message: "UserDefaults changed: \(key)",
            metadata: meta)
        
        NSLog("[STORAGE] UserDefaults - key: %@, value: %@, user_id: %@",
              key, value.map { "\($0)" } ?? "nil", userId ?? "anonymous")
    }
    
    // MARK: - Utility
    
    func exportLogs() -> [LogEntry] {
        return logBuffer
    }
    
    func getLogFileContents() -> String? {
        guard let url = logFileURL else { return nil }
        return try? String(contentsOf: url, encoding: .utf8)
    }
    
    func clearLogs() {
        logQueue.async { [weak self] in
            self?.logBuffer.removeAll()
            if let url = self?.logFileURL {
                try? FileManager.default.removeItem(at: url)
            }
        }
        NSLog("[ANALYTICS] Logs cleared by user %@", userId ?? "unknown")
    }
}

// MARK: - URLSession Extension for Automatic Network Logging

extension URLSession {
    func loggedDataTask(with request: URLRequest, completionHandler: @escaping (Data?, URLResponse?, Error?) -> Void) -> URLSessionDataTask {
        let requestId = UUID().uuidString
        let startTime = Date()
        
        AnalyticsLogger.shared.logNetworkRequest(request, requestId: requestId)
        
        return dataTask(with: request) { data, response, error in
            let duration = Date().timeIntervalSince(startTime)
            AnalyticsLogger.shared.logNetworkResponse(
                response as? HTTPURLResponse,
                data: data,
                error: error,
                duration: duration,
                requestId: requestId,
                originalRequest: request
            )
            completionHandler(data, response, error)
        }
    }
}

// MARK: - Performance Timer Helper

class PerformanceTimer {
    private let name: String
    private let startTime: Date
    private var metadata: [String: String]
    
    init(name: String, metadata: [String: String] = [:]) {
        self.name = name
        self.startTime = Date()
        self.metadata = metadata
        
        NSLog("[PERF_TIMER] Started: %@", name)
        print("⏱ Timer started: \(name)")
    }
    
    func stop() {
        let duration = Date().timeIntervalSince(startTime)
        AnalyticsLogger.shared.logPerformanceMetric(name: name, duration: duration, metadata: metadata)
    }
    
    func addMetadata(key: String, value: String) {
        metadata[key] = value
    }
}

